means = {}
for hist, lst in vals_by_hist.items():
    if len(lst) == 0:
        continue
    m = sum(lst) / len(lst)
    # keep 6 decimal places for safety
    means[hist] = round(m, 6)

# Sort keys for consistent output
out = {k: means[k] for k in sorted(means.keys())}

result_str = json.dumps(out)
